//! Automatic mock generation for external dependencies.
//!
//! Classifies external dependencies into categories (I/O, library, utility)
//! and generates sensible default [`MockConfig`]s without requiring user
//! configuration. Users can override defaults via `.shatter/config.yaml`.

use std::collections::HashMap;

use serde_json::{json, Value};

use crate::protocol::{ExternalDependency, MockBehavior, MockConfig};
use crate::scope::{DependencyAction, ScopeMatcher};
use crate::types::TypeInfo;

/// Category of an external dependency, used to select default mock behavior.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum IoCategory {
    /// File system operations (fs, path).
    FileSystem,
    /// Network operations (http, fetch, axios, net).
    Network,
    /// Database operations (pg, mysql, mongodb, redis, prisma, knex).
    Database,
    /// Pure utility functions (lodash, ramda, date-fns) — safe to call.
    PureUtility,
    /// Other external library — use type-aware stub.
    ExternalOther,
}

/// Known module prefixes for each category.
const FS_MODULES: &[&str] = &[
    "fs", "node:fs", "fs/promises", "node:fs/promises", "path", "node:path",
    // Go stdlib
    "os", "io", "io/ioutil", "bufio",
];
const NETWORK_MODULES: &[&str] = &[
    "http", "https", "node:http", "node:https", "net", "node:net",
    "axios", "node-fetch", "fetch", "got", "superagent", "request",
    "undici",
];
const DB_MODULES: &[&str] = &[
    "pg", "mysql", "mysql2", "mongodb", "redis", "ioredis",
    "prisma", "@prisma/client", "knex", "sequelize", "typeorm",
    "mongoose", "sqlite3", "better-sqlite3", "drizzle-orm",
    "database/sql", "gorm.io/gorm",
];
const PURE_UTILITY_MODULES: &[&str] = &[
    "lodash", "lodash-es", "underscore", "ramda", "date-fns",
    "dayjs", "moment", "validator", "uuid", "nanoid",
    "chalk", "debug", "ms",

//! Compositional mock generation from behavior maps.
//!
//! When function A calls function B and B's [`BehaviorMap`] is available,
//! this module builds an input-conditional decision tree that produces
//! high-fidelity mocks: given the same arguments B received during
//! exploration, the mock returns the same value (or throws the same error).
//!
//! The flat [`MockConfig`] format cycles through return values in order,
//! ignoring what the caller actually passes. A [`MockDecisionTree`] instead
//! matches each call's arguments against observed input patterns and picks
//! the correct output, falling back to a default when no pattern matches.

use serde::{Deserialize, Serialize};

use crate::behavior::{Behavior, BehaviorMap};
use crate::protocol::{MockBehavior, MockConfig};

// ---------------------------------------------------------------------------
// Pattern matching types
// ---------------------------------------------------------------------------

/// How to match a single argument value.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum PatternMatcher {
    /// Exact JSON equality.
    Eq { value: serde_json::Value },
    /// Numeric range (inclusive on both ends).
    Range { min: f64, max: f64 },
    /// Match by JSON type name ("number", "string", "boolean", "null", "array", "object").
    Type { type_name: String },
    /// Match anything.
    Any,
}

/// A condition on one argument of the mocked function.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct InputPattern {
    /// Zero-based index of the argument to check.
    pub arg_index: usize,
    /// How to match the argument.
    pub matcher: PatternMatcher,
}

/// A single branch of the decision tree: if all input patterns match,
/// return `return_value` (or throw `error`).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MockCondition {
    /// Patterns that must all match for this condition to fire.
    pub input_patterns: Vec<InputPattern>,

