275→/// Generate a Date value as `{"__complex_type": "date", "value": <epoch_ms>}`.
276→///
277→/// Biased toward boundary values: epoch 0, Y2K38, month/year boundaries, etc.
278→fn generate_date(rng: &mut impl Rng) -> Value {
279→    let choice: u8 = rng.random_range(0..12);
280→    let epoch_ms: i64 = match choice {
281→        0 => 0,                        // Unix epoch
282→        1 => -1,                       // Just before epoch
283→        2 => 2_147_483_647_000,        // Y2K38 (2038-01-19T03:14:07Z) in ms
284→        3 => 1_704_067_200_000,        // 2024-01-01T00:00:00Z
285→        4 => 946_684_800_000,          // 2000-01-01T00:00:00Z (Y2K)
286→        5 => -62_135_596_800_000,      // 0001-01-01T00:00:00Z (far past)
287→        6 => 253_402_300_799_000,      // 9999-12-31T23:59:59Z (far future)
288→        7 => 1_609_459_200_000,        // 2021-01-01T00:00:00Z
289→        8 => {
290→            // Random month boundary: 1st of a random month in 2020-2025
291→            let year = rng.random_range(2020..=2025);
292→            let month = rng.random_range(1..=12);
293→            // Approximate: months * 30.44 days
294→            let days_since_epoch = (year - 1970) * 365 + (month - 1) * 30;
295→            days_since_epoch as i64 * 86_400_000
296→        }
297→        9 => -86_400_000,             // One day before epoch
298→        10 => 86_400_000,             // One day after epoch
299→        _ => {
300→            // Random date between 1970 and 2030
301→            rng.random_range(0..1_893_456_000_000_i64)
302→        }
303→    };
304→    json!({"__complex_type": "date", "value": epoch_ms})
305→}
