217→/// Scope-aware path hash that collapses repeated loop/call scopes.
218→///
219→/// Parses the flat trace into a tree of nested scopes, then for each scope_id
220→/// that appears multiple times at the same nesting level, collapses all
221→/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
222→/// When `buckets` is non-empty, each distinct profile is also paired with
223→/// its iteration-count bucket so that different iteration counts produce
224→/// different hashes.
225→fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
226→    use crate::execution_record::{ScopeEvent, TraceEvent};
227→    use std::collections::BTreeSet;
228→
229→    /// Discriminant tag for scope enter/exit matching.
230→    #[derive(Clone, Copy, PartialEq)]
231→    enum ScopeKind {
232→        Loop(u32),
233→        Call(u32),
234→    }
235→
236→    /// A sorted branch profile from one loop/call iteration.
237→    type BranchProfile = Vec<(u32, bool)>;
238→
239→    /// A profile paired with its optional iteration-count bucket.
240→    type ProfileWithBucket = (BranchProfile, Option<u32>);
241→
242→    /// Collapsed representation of a scope's content for hashing.
243→    #[derive(Hash)]
244→    enum CollapsedItem {
245→        /// A branch decision outside any scope at this level.
246→        Branch { branch_id: u32, taken: bool },
247→        /// A collapsed scope: set of distinct per-iteration branch profiles,
248→        /// each paired with its iteration-count bucket (or `None` when
249→        /// bucketing is disabled, preserving backward-compat hashing).
250→        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
251→    }
252→
253→    fn is_matching_exit(event: &TraceEvent, kind: ScopeKind) -> bool {
254→        match (kind, event) {
255→            (ScopeKind::Loop(id), TraceEvent::Scope { event: ScopeEvent::LoopExit { loop_id } }) => *loop_id == id,
256→            (ScopeKind::Call(id), TraceEvent::Scope { event: ScopeEvent::CallExit { call_site_id } }) => *call_site_id == id,
257→            _ => false,
258→        }
259→    }
260→
261→    /// Convert accumulated per-scope profile maps into `CollapsedItem::Scope`
262→    /// entries appended to `items`. Called at both the normal end of `collapse()`
263→    /// and the early return on parent-scope exit — without this, nested scopes
264→    /// would be invisible to their parent's branch profile.
265→    fn emit_scope_items(
266→        items: &mut Vec<CollapsedItem>,
267→        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
268→        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
269→        buckets: &LoopBuckets,
270→    ) {
271→        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
272→        for (id, profiles) in loop_profiles {
273→            let tag = (*id as u64) | (1u64 << 32);
274→            let mut sorted: Vec<ProfileWithBucket> = profiles
275→                .iter()
276→                .map(|(profile, &count)| {
277→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
278→                    (profile.clone(), bucket)
279→                })
280→                .collect();
281→            sorted.sort();
282→            scope_ids.push((tag, sorted));
283→        }
284→        for (id, profiles) in call_profiles {
285→            let tag = (*id as u64) | (2u64 << 32);
286→            let mut sorted: Vec<ProfileWithBucket> = profiles
287→                .iter()
288→                .map(|(profile, &count)| {
289→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
290→                    (profile.clone(), bucket)
291→                })
292→                .collect();
293→            sorted.sort();
294→            scope_ids.push((tag, sorted));
295→        }
296→        scope_ids.sort_by_key(|(tag, _)| *tag);
297→        for (scope_tag, profile_buckets) in scope_ids {
298→            items.push(CollapsedItem::Scope { scope_tag, profile_buckets });
299→        }
300→    }

