647→            rng.random_range(1..=100) as i64,
648→        ),
649→    };
650→    json!({"__complex_type": "rational", "numerator": num, "denominator": den})
651→}
652→
653→/// Generate a BitSet value.
654→fn generate_bitset(rng: &mut impl Rng) -> Value {
655→    let choice: u8 = rng.random_range(0..4);
656→    let (bits, length): (&str, u32) = match choice {
657→        0 => ("00000000", 8),   // all zeros
658→        1 => ("11111111", 8),   // all ones
659→        2 => ("10000000", 8),   // single bit
660→        _ => ("10101010", 8),   // alternating
661→    };
662→    json!({"__complex_type": "bit_set", "bits": bits, "length": length})
663→}
664→
665→/// Generate an Option value (None ~30%, Some ~70%).
666→fn generate_option(rng: &mut impl Rng) -> Value {
667→    if rng.random_range(0..10) < 3 {
668→        json!({"__complex_type": "option", "present": false})
669→    } else {
670→        let inner = generate_int(rng);
671→        json!({"__complex_type": "option", "present": true, "value": inner})
672→    }
673→}
674→
675→/// Generate a Result value (Ok ~70%, Err ~30%).
676→fn generate_result(rng: &mut impl Rng) -> Value {
677→    if rng.random_range(0..10) < 3 {
678→        json!({"__complex_type": "result", "ok": false, "error": "error"})
679→    } else {
680→        let inner = generate_int(rng);
681→        json!({"__complex_type": "result", "ok": true, "value": inner})
682→    }
683→}
684→
685→/// Generate a Closure value (canned variant).
686→fn generate_closure(rng: &mut impl Rng) -> Value {
687→    let variants = ["identity", "constant", "thrower"];
688→    let idx = rng.random_range(0..variants.len());
689→    json!({"__complex_type": "closure", "variant": variants[idx]})
690→}
691→
692→/// Generate an Iterator value (array of values the frontend wraps).
693→fn generate_iterator(rng: &mut impl Rng) -> Value {
694→    let len = rng.random_range(0..=5);
695→    let values: Vec<Value> = (0..len).map(|_| generate_int(rng)).collect();
696→    json!({"__complex_type": "iterator", "values": values})
697→}
698→
699→/// For unknown types, generate a random value from any primitive type.
700→fn generate_unknown(rng: &mut impl Rng) -> Value {
701→    let choice: u8 = rng.random_range(0..4);
702→    match choice {
703→        0 => generate_int(rng),
704→        1 => generate_float(rng),
705→        2 => generate_string(rng),
706→        3 => json!(rng.random_bool(0.5)),
707→        _ => unreachable!(),
708→    }
709→}
710→
711→/// Generate a complete set of random inputs for a function's parameters.
712→///
713→/// When `caps` is provided, complex types are only generated if the frontend
714→/// declared support; otherwise they fall back to unknown/primitive generation.
715→pub fn generate_random_inputs(
716→    params: &[crate::types::ParamInfo],
717→    rng: &mut impl Rng,
718→    caps: Option<&FrontendCapabilities>,
719→) -> Vec<Value> {
720→    params
721→        .iter()
722→        .map(|p| {
723→            if matches!(p.typ, TypeInfo::Str) {
724→                let hint = heuristic_string_for_name(&p.name)
725→                    .or_else(|| p.type_name.as_deref().and_then(heuristic_string_for_name));
726→                if let Some(val) = hint {
727→                    return json!(val);
728→                }
729→            }
730→            generate_random_value(&p.typ, rng, caps)
731→        })
732→        .collect()
733→}
734→
735→// ---------------------------------------------------------------------------
736→// Float-biased input generation
737→// ---------------------------------------------------------------------------
738→
739→/// Generate a float value biased toward integers.
740→///
741→/// With probability `integer_ratio`, generates an integer (as f64).
742→/// Otherwise delegates to the standard `generate_float()` distribution.
743→pub fn generate_biased_float(rng: &mut impl Rng, integer_ratio: f64) -> Value {
744→    if rng.random_bool(integer_ratio.clamp(0.0, 1.0)) {
745→        // Generate as integer
746→        let n = rng.random_range(-1000..=1000) as f64;
747→        json!(n)
748→    } else {
749→        generate_float(rng)
750→    }
751→}
752→
753→/// Like [`generate_random_inputs`] but applies integer bias to Float params
754→/// classified as `IntegerTreating`.
755→pub fn generate_random_inputs_with_float_bias(
756→    params: &[crate::types::ParamInfo],
757→    float_bias: &std::collections::HashMap<usize, crate::float_probe::FloatClassification>,
758→    rng: &mut impl Rng,
759→    caps: Option<&FrontendCapabilities>,
760→) -> Vec<Value> {
761→    params
762→        .iter()
763→        .enumerate()
764→        .map(|(i, p)| {
765→            if matches!(p.typ, TypeInfo::Str) {
766→                let hint = heuristic_string_for_name(&p.name)
767→                    .or_else(|| p.type_name.as_deref().and_then(heuristic_string_for_name));
768→                if let Some(val) = hint {
769→                    return json!(val);
770→                }
771→            }
772→            if matches!(p.typ, TypeInfo::Float)
773→                && float_bias.get(&i)
774→                    == Some(&crate::float_probe::FloatClassification::IntegerTreating)
775→            {
776→                return generate_biased_float(rng, crate::float_probe::INTEGER_BIAS_RATIO);
777→            }
778→            generate_random_value(&p.typ, rng, caps)
779→        })
780→        .collect()
781→}
