786→
787→/// Where a parameter's value should come from during input generation.
788→#[derive(Debug, Clone, PartialEq)]
789→pub enum ValueSource {
790→    /// Use a custom generator file to produce values for this parameter.
791→    CustomGenerator {
792→        /// Name of the generator (type name or param name, used for protocol).
793→        generator_name: String,
794→        /// The parameter name, if this is a param-level generator.
795→        param_name: Option<String>,
796→        /// Absolute path to the generator file.
797→        generator_file: std::path::PathBuf,
798→        /// Whether this targets a type name or a parameter name.
799→        kind: crate::protocol::GeneratorKind,
800→    },
801→    /// Fall back to built-in random generation.
802→    BuiltIn,
803→}
804→
805→/// Determine the value source for each parameter based on resolved config.
806→///
807→/// Priority: `param_generators` (exact name match) > `type_generators` (type_name match) > `BuiltIn`.
808→pub fn resolve_value_sources(
809→    params: &[crate::types::ParamInfo],
810→    param_generators: &std::collections::HashMap<String, std::path::PathBuf>,
811→    type_generators: &std::collections::HashMap<String, std::path::PathBuf>,
812→) -> Vec<ValueSource> {
813→    params
814→        .iter()
815→        .map(|p| {
816→            // 1. Check param_generators by parameter name
817→            if let Some(gen_path) = param_generators.get(&p.name) {
818→                return ValueSource::CustomGenerator {
819→                    generator_name: p.name.clone(),
820→                    param_name: Some(p.name.clone()),
821→                    generator_file: gen_path.clone(),
822→                    kind: crate::protocol::GeneratorKind::ParamName,
823→                };
824→            }
825→            // 2. Check type_generators by type_name
826→            if let Some(gen_path) = p.type_name.as_ref().and_then(|tn| type_generators.get(tn)) {
827→                return ValueSource::CustomGenerator {
828→                    generator_name: p.type_name.clone().unwrap_or_default(),
829→                    param_name: None,
830→                    generator_file: gen_path.clone(),
831→                    kind: crate::protocol::GeneratorKind::TypeName,
832→                };
833→            }
834→            // 3. Built-in
835→            ValueSource::BuiltIn
836→        })
837→        .collect()
838→}
839→
840→/// A single value produced by a custom generator, with replay metadata.
841→#[derive(Debug, Clone)]
842→pub struct GeneratedEntry {
843→    /// The generated value (JSON).
844→    pub value: Value,
845→    /// Human-readable label from the generator.
846→    pub generator_id: String,
847→    /// Serializable recipe for replaying this generation.
848→    /// For WASM generators where value IS the recipe, this is `None`.
849→    pub recipe: Option<Value>,
850→    /// Composite ID: `"{generator_id}@{recipe_hash}"`.
851→    pub composite_id: String,
852→}
853→
854→/// Pre-fetched values from custom generators, keyed by `(generator_file, generator_name)`.
855→///
856→/// Each entry holds a queue of generated entries that can be drawn from during
857→/// input generation. When the queue is empty, generation falls back to built-in.
858→#[derive(Debug, Default)]
859→pub struct PrefetchedValues {
860→    /// Map from (generator file path as string, generator name) to queued entries.
861→    entries: std::collections::HashMap<(String, String), Vec<GeneratedEntry>>,
862→}
863→
864→impl PrefetchedValues {
865→    /// Create an empty prefetch store.
866→    #[must_use]
867→    pub fn new() -> Self {
868→        Self {
869→            entries: std::collections::HashMap::new(),
870→        }
871→    }
872→
873→    /// Insert generated values for a specific generator (legacy API, no metadata).
874→    pub fn insert(&mut self, file: String, name: String, vals: Vec<Value>) {
875→        let entries: Vec<GeneratedEntry> = vals
876→            .into_iter()
877→            .map(|v| {
878→                let composite = crate::canonical_json::composite_id("unknown", &v);
879→                GeneratedEntry {
880→                    value: v,
881→                    generator_id: "unknown".into(),
882→                    recipe: None,
883→                    composite_id: composite,
884→                }
885→            })
886→            .collect();
887→        self.entries.entry((file, name)).or_default().extend(entries);
888→    }
889→
890→    /// Insert a fully-formed generated entry with metadata.
891→    pub fn insert_entry(&mut self, file: String, name: String, entry: GeneratedEntry) {
892→        self.entries.entry((file, name)).or_default().push(entry);
893→    }
894→
895→    /// Take the next value for a generator, if available.
896→    pub fn take(&mut self, file: &str, name: &str) -> Option<Value> {
897→        self.take_entry(file, name).map(|e| e.value)
898→    }
