  1→/**
  2→ * TypeScript function analyzer using the TypeScript Compiler API.
  3→ *
  4→ * Given a file path and optional function name, extracts parameter types,
  5→ * return type, and source location for exported functions.
  6→ */
  7→
  8→import * as ts from "typescript";
  9→import * as path from "node:path";
 10→import type {
 11→  FunctionAnalysis,
 12→  ParamInfo,
 13→  TypeInfo,
 14→  BranchInfo,
 15→  BranchType,
 16→  SymExpr,
 17→  BinOpKind,
 18→  UnOpKind,
 19→  ExternalDependency,
 20→  DependencyKind,
 21→  LiteralValue,
 22→} from "./protocol.js";
 23→
 24→function hasExportModifier(node: ts.Node): boolean {
 25→  const modifiers = ts.canHaveModifiers(node) ? ts.getModifiers(node) : undefined;
 26→  return modifiers?.some((m) => m.kind === ts.SyntaxKind.ExportKeyword) ?? false;
 27→}
 28→
 29→/** Default compiler options used when no tsconfig.json is available. */
 30→const DEFAULT_COMPILER_OPTIONS: ts.CompilerOptions = {
 31→  target: ts.ScriptTarget.ES2022,
 32→  module: ts.ModuleKind.Node16,
 33→  strict: true,
 34→  noEmit: true,
 35→  allowJs: true,
 36→  jsx: ts.JsxEmit.ReactJSX,
 37→};
 38→
 39→/**
 40→ * Load compiler options from tsconfig.json if a project root is provided,
 41→ * falling back to hardcoded defaults on any error or when no root is given.
 42→ */
 43→function loadCompilerOptions(absoluteFilePath: string, projectRoot?: string): ts.CompilerOptions {
 44→  if (!projectRoot) {
 45→    return DEFAULT_COMPILER_OPTIONS;
 46→  }
 47→
 48→  const tsconfigPath = path.join(projectRoot, "tsconfig.json");
 49→  const readResult = ts.readConfigFile(tsconfigPath, ts.sys.readFile);
 50→  if (readResult.error) {
 51→    return DEFAULT_COMPILER_OPTIONS;
 52→  }
 53→
 54→  const parsed = ts.parseJsonConfigFileContent(
 55→    readResult.config,
 56→    ts.sys,
 57→    projectRoot,
 58→  );
 59→
 60→  if (parsed.errors.length > 0) {
 61→    return DEFAULT_COMPILER_OPTIONS;
 62→  }
 63→
 64→  // Preserve critical defaults that shatter needs
 65→  return {
 66→    ...parsed.options,
 67→    noEmit: true,
 68→    allowJs: true,
 69→  };
 70→}
 71→
 72→/**
 73→ * Analyze functions in a TypeScript file.
 74→ *
 75→ * If `functionName` is provided, only that function is returned.
 76→ * Otherwise, all top-level exported functions are returned.
 77→ */
 78→export function analyzeFile(filePath: string, functionName?: string | null, projectRoot?: string | null): FunctionAnalysis[] {
 79→  const absolutePath = path.resolve(filePath);
 80→  const compilerOptions = loadCompilerOptions(absolutePath, projectRoot ?? undefined);
 81→  const program = ts.createProgram([absolutePath], compilerOptions);
 82→
 83→  const sourceFile = program.getSourceFile(absolutePath);
 84→  if (!sourceFile) {
 85→    return [];
 86→  }
 87→
 88→  const checker = program.getTypeChecker();
 89→  const results: FunctionAnalysis[] = [];
 90→
 91→  // Collect CommonJS-exported names so we can mark them as exported
 92→  const commonJsExportedNames = collectCommonJsExports(sourceFile);
 93→
 94→  ts.forEachChild(sourceFile, (node) => {
 95→    if (ts.isFunctionDeclaration(node)) {
 96→      if (node.name) {
 97→        const name = node.name.text;
 98→        if (functionName != null && name !== functionName) {
 99→          return;
100→        }
101→        const exported = hasExportModifier(node) || commonJsExportedNames.has(name);
102→        const analysis = analyzeFunctionDeclaration(node, checker, sourceFile, exported);
103→        if (analysis) {
104→          results.push(analysis);
105→        }
106→      } else if (hasExportModifier(node)) {
107→        // Unnamed default export: export default function(...) {}
108→        const syntheticName = "<default>";
109→        if (functionName != null && syntheticName !== functionName) {
110→          return;
111→        }
112→        const analysis = analyzeFunctionDeclarationUnnamed(node, syntheticName, checker, sourceFile);
113→        if (analysis) {
114→          results.push(analysis);
115→        }
116→      }
117→      return;
118→    }
119→
120→    if (ts.isVariableStatement(node)) {
121→      const exported = hasExportModifier(node);
122→      for (const decl of node.declarationList.declarations) {
123→        if (!ts.isIdentifier(decl.name)) continue;
124→        const name = decl.name.text;
125→        if (functionName != null && name !== functionName) continue;
126→
127→        if (decl.initializer && ts.isArrowFunction(decl.initializer)) {
128→          const analysis = analyzeArrowFunction(name, decl.initializer, checker, sourceFile, exported);
129→          if (analysis) {
130→            results.push(analysis);
131→          }
132→        } else if (decl.initializer && ts.isFunctionExpression(decl.initializer)) {
133→          const analysis = analyzeFunctionExpression(name, decl.initializer, checker, sourceFile, exported);
134→          if (analysis) {
135→            results.push(analysis);
136→          }
137→        }
138→      }
139→      return;
140→    }
141→
142→    // CommonJS: exports.foo = function(...) {}
143→    if (ts.isExpressionStatement(node) && ts.isBinaryExpression(node.expression)) {
144→      const bin = node.expression;
145→      if (bin.operatorToken.kind === ts.SyntaxKind.EqualsToken &&
146→          ts.isPropertyAccessExpression(bin.left) &&
147→          ts.isIdentifier(bin.left.expression) &&
148→          bin.left.expression.text === "exports") {
149→        const name = bin.left.name.text;
150→        if (functionName != null && name !== functionName) return;
151→        if (ts.isFunctionExpression(bin.right)) {
152→          const analysis = analyzeFunctionExpression(name, bin.right, checker, sourceFile, true);
153→          if (analysis) results.push(analysis);
154→        } else if (ts.isArrowFunction(bin.right)) {
155→          const analysis = analyzeArrowFunction(name, bin.right, checker, sourceFile, true);
156→          if (analysis) results.push(analysis);
157→        }
158→      }
159→    }
160→  });
161→
162→  return results;
163→}
164→
165→function analyzeFunctionDeclaration(
166→  node: ts.FunctionDeclaration,
167→  checker: ts.TypeChecker,
168→  sourceFile: ts.SourceFile,
169→  exported: boolean,
170→): FunctionAnalysis | null {
171→  if (!node.name) return null;
172→
173→  const name = node.name.text;
174→  const params = node.parameters.map((p) => analyzeParameter(p, checker));
175→  const paramNames = new Set(params.map((p) => p.name));
176→
177→  const sig = checker.getSignatureFromDeclaration(node);
178→  const returnType = sig
179→    ? convertType(checker.getReturnTypeOfSignature(sig), checker)
180→    : { kind: "unknown" as const };
181→
182→  const startLine = sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
183→  const endLine = sourceFile.getLineAndCharacterOfPosition(node.getEnd()).line + 1;
184→
185→  const branches = node.body ? extractBranches(node.body, sourceFile, paramNames) : [];
186→  const dependencies = node.body ? extractDependencies(node.body, checker, sourceFile, paramNames) : [];
187→  const literals = extractLiterals(node, sourceFile, checker);
188→
189→  return {
190→    name,
191→    exported,
192→    params,
193→    branches,
194→    dependencies,
195→    return_type: returnType,
196→    start_line: startLine,
197→    end_line: endLine,
198→    ...(literals.length > 0 ? { literals } : {}),
199→  };
200→}

637→
638→/**
639→ * Walk a function body and detect calls to external (imported/other-file) functions.
640→ */
641→function extractDependencies(
642→  body: ts.Block,
643→  checker: ts.TypeChecker,
644→  sourceFile: ts.SourceFile,
645→  paramNames: Set<string>,
646→): ExternalDependency[] {
647→  const accumulators = new Map<string, DependencyAccumulator>();
648→
649→  walkForDependencies(body, checker, sourceFile, paramNames, accumulators);
650→
651→  return Array.from(accumulators.values()).map((acc) => ({
652→    kind: acc.kind,
653→    symbol: acc.symbol,
654→    source_module: acc.sourceModule,
655→    return_type: acc.returnType,
656→    param_types: acc.paramTypes,
657→    call_sites: acc.callSites,
658→  }));
659→}
660→
661→function walkForDependencies(
662→  node: ts.Node,
663→  checker: ts.TypeChecker,
664→  sourceFile: ts.SourceFile,
665→  paramNames: Set<string>,
666→  accumulators: Map<string, DependencyAccumulator>,
667→): void {
668→  if (ts.isCallExpression(node)) {
669→    const callee = node.expression;
670→    const line = sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
671→
672→    let symbol: ts.Symbol | undefined;
673→    let depKind: DependencyKind = "function_call";
674→    let symbolName: string | undefined;
675→
676→    if (ts.isIdentifier(callee)) {
677→      symbol = checker.getSymbolAtLocation(callee);
678→      symbolName = callee.text;
679→    } else if (ts.isPropertyAccessExpression(callee)) {
680→      symbol = checker.getSymbolAtLocation(callee.name);
681→      symbolName = callee.getText(sourceFile);
682→      depKind = "method_call";
683→    }
684→
685→    if (symbol && symbolName) {
686→      const resolvedSymbol = resolveAliasedSymbol(symbol, checker);
687→      const declSourceFile = getDeclarationSourceFile(resolvedSymbol);
688→
689→      if (declSourceFile && declSourceFile !== sourceFile.fileName) {
690→        const sourceModule = formatSourceModule(declSourceFile, sourceFile.fileName);
691→        const key = `${symbolName}::${sourceModule}`;
692→
693→        const existing = accumulators.get(key);
694→        if (existing) {
695→          existing.callSites.push(line);
696→        } else {
697→          const sig = checker.getResolvedSignature(node);
698→          const returnType = sig
699→            ? convertType(checker.getReturnTypeOfSignature(sig), checker)
700→            : { kind: "unknown" as const };
701→          const paramTypesArr: TypeInfo[] = sig
702→            ? sig.getParameters().map((p) => convertType(checker.getTypeOfSymbolAtLocation(p, node), checker))
703→            : [];
704→
705→          accumulators.set(key, {
706→            kind: depKind,
707→            symbol: symbolName,
708→            sourceModule,
709→            returnType,
710→            paramTypes: paramTypesArr,
711→            callSites: [line],
712→          });
713→        }
714→      }
715→    }
716→  }
717→
718→  ts.forEachChild(node, (child) =>
719→    walkForDependencies(child, checker, sourceFile, paramNames, accumulators),
720→  );
721→}
722→
723→/**
724→ * Follow alias chains (import aliases) to the original symbol.
725→ */
726→function resolveAliasedSymbol(symbol: ts.Symbol, checker: ts.TypeChecker): ts.Symbol {
727→  if (symbol.flags & ts.SymbolFlags.Alias) {
728→    return checker.getAliasedSymbol(symbol);
729→  }
730→  return symbol;
731→}
732→
733→/**
734→ * Get the file name of a symbol's declaration, or undefined if unknown.
735→ */
736→function getDeclarationSourceFile(symbol: ts.Symbol): string | undefined {
737→  const declarations = symbol.getDeclarations();
738→  if (declarations && declarations.length > 0) {
739→    return declarations[0]!.getSourceFile().fileName;
740→  }
741→  return undefined;
742→}
743→
744→/**
745→ * Format a source module path relative to the current file, producing a
746→ * human-readable module specifier.
747→ */
748→function formatSourceModule(declFile: string, currentFile: string): string {
749→  // For node_modules, extract the package name
750→  const nodeModulesIdx = declFile.lastIndexOf("node_modules/");
751→  if (nodeModulesIdx !== -1) {
752→    const afterNodeModules = declFile.substring(nodeModulesIdx + "node_modules/".length);
753→    // Handle scoped packages (@scope/name)
754→    if (afterNodeModules.startsWith("@")) {
755→      const parts = afterNodeModules.split("/");
756→      if (parts.length >= 2) {
757→        return `${parts[0]}/${parts[1]}`;
758→      }
759→    }
760→    const firstSlash = afterNodeModules.indexOf("/");
761→    return firstSlash === -1 ? afterNodeModules : afterNodeModules.substring(0, firstSlash);
762→  }
763→
764→  // For project files, compute relative path
765→  const rel = path.relative(path.dirname(currentFile), declFile);
766→  const withoutExt = rel.replace(/\.(ts|tsx|js|jsx|d\.ts)$/, "");
767→  return withoutExt.startsWith(".") ? withoutExt : `./${withoutExt}`;
768→}
