 54→/// Errors during recursive exploration.
 55→#[derive(Debug, thiserror::Error)]
 56→pub enum RecursiveError {
 57→    #[error("frontend error: {0}")]
 58→    Frontend(#[from] FrontendError),
 59→    #[error("unexpected response from frontend: {0}")]
 60→    UnexpectedResponse(String),
 61→    #[error("no base cases found after probing")]
 62→    NoBaseCases,
 63→}
 64→
 65→/// Generate canonical probe values for a type.
 66→///
 67→/// Returns small/boundary values likely to trigger base cases in recursive
 68→/// functions (e.g., 0, 1, -1 for numbers; "" for strings; [] for arrays).
 69→fn probe_values(typ: &TypeInfo) -> Vec<Value> {
 70→    match typ {
 71→        TypeInfo::Int => vec![json!(0), json!(1), json!(-1), json!(2)],
 72→        TypeInfo::Float => vec![json!(0.0), json!(1.0), json!(-1.0), json!(0.5)],
 73→        TypeInfo::Str => vec![json!(""), json!("a")],
 74→        TypeInfo::Bool => vec![json!(false), json!(true)],
 75→        TypeInfo::Array { .. } => vec![json!([]), json!([1])],
 76→        TypeInfo::Object { fields } => {
 77→            // Single probe: object with minimal field values
 78→            let mut obj = serde_json::Map::new();
 79→            for (name, field_typ) in fields {
 80→                let vals = probe_values(field_typ);
 81→                if let Some(v) = vals.into_iter().next() {
 82→                    obj.insert(name.clone(), v);
 83→                }
 84→            }
 85→            vec![Value::Object(obj)]
 86→        }
 87→        TypeInfo::Union { variants } => {
 88→            // Probe values from each variant
 89→            variants.iter().flat_map(probe_values).collect()
 90→        }
 91→        TypeInfo::Nullable { inner } => {
 92→            let mut vals = vec![Value::Null];
 93→            vals.extend(probe_values(inner));
 94→            vals
 95→        }
 96→        // Complex types use same probes as Unknown for now
 97→        TypeInfo::Complex { .. } => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
 98→        // Opaque types cannot be constructed; use same fallback probes as Unknown
 99→        TypeInfo::Opaque { .. } => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
100→        TypeInfo::Unknown => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
101→    }
102→}
103→
104→/// Generate combinatorial probe inputs for a function, capped at `max_probes`.
105→///
106→/// For single-parameter functions, returns probe values directly.
107→/// For multi-parameter functions, takes the cartesian product, capped.
108→fn generate_probe_inputs(params: &[crate::types::ParamInfo], max_probes: usize) -> Vec<Vec<Value>> {
109→    if params.is_empty() {
110→        return vec![vec![]];
111→    }
112→
113→    let per_param: Vec<Vec<Value>> = params.iter().map(|p| probe_values(&p.typ)).collect();
114→
115→    // Cartesian product with budget cap
116→    let mut results: Vec<Vec<Value>> = vec![vec![]];
117→    for param_vals in &per_param {
118→        let mut next = Vec::new();
119→        for existing in &results {
120→            for val in param_vals {
121→                if next.len() >= max_probes {
122→                    return next;
123→                }
124→                let mut combo = existing.clone();
125→                combo.push(val.clone());
126→                next.push(combo);
127→            }
128→        }
129→        results = next;
130→    }
131→
132→    results
133→}
134→
135→/// Probe a self-recursive function with small values to find base cases.
136→///
137→/// Executes the function with no mocks. Executions that don't call the function
138→/// itself are base cases. Returns execution records for base-case executions.
139→async fn probe_for_base_cases(
140→    frontend: &mut Frontend,
141→    analysis: &FunctionAnalysis,
142→    config: &RecursiveConfig,
143→) -> Result<(Vec<ExecutionRecord>, usize), RecursiveError> {
144→    let probe_inputs = generate_probe_inputs(&analysis.params, config.max_probes);
145→    let mut base_cases = Vec::new();
146→    let mut probes_executed = 0;
147→
148→    for inputs in probe_inputs {
149→        probes_executed += 1;
150→
151→        let response = frontend
152→            .send(ProtoCommand::Execute {
153→                function: analysis.name.clone(),
154→                inputs: inputs.clone(),
155→                mocks: vec![],
156→                setup_context: None,
157→            })
158→            .await?;
159→
160→        let exec_result = match response.result {
161→            ResponseResult::Execute(result) => result,
162→            ResponseResult::Error { code, message, .. } => {
163→                return Err(RecursiveError::UnexpectedResponse(format!(
164→                    "execute error ({code:?}): {message}"
165→                )));
166→            }
167→            other => {
168→                return Err(RecursiveError::UnexpectedResponse(format!("{other:?}")));
169→            }
170→        };
171→
172→        // A base case: the function didn't call itself
173→        let calls_self = exec_result
174→            .calls_to_external
175→            .iter()
176→            .any(|c| c.symbol == analysis.name);
177→
178→        if !calls_self {
179→            let input_hash = hash_inputs(&inputs);
180→            base_cases.push(make_exec_record(&analysis.name, input_hash, inputs, &exec_result));
181→        }
182→    }
183→
184→    Ok((base_cases, probes_executed))
185→}
186→
187→/// Explore a self-recursive function by iterative deepening.
188→///
189→/// 1. Probe with small values to find base cases (depth 0).
190→/// 2. For each subsequent depth, mock self-calls using the BehaviorMap from
191→///    all previous depths and execute with random inputs.
192→/// 3. Stop when no new behaviors are discovered or max_depth is reached.
193→pub async fn explore_recursive(
194→    frontend: &mut Frontend,
195→    analysis: &FunctionAnalysis,
196→    config: &RecursiveConfig,
197→) -> Result<RecursiveResult, RecursiveError> {
198→    // Step 1: Probe for base cases
199→    let (base_records, probes_executed) =
200→        probe_for_base_cases(frontend, analysis, config).await?;
201→    let base_case_count = base_records.len();
202→
203→    if base_records.is_empty() {
204→        return Err(RecursiveError::NoBaseCases);
205→    }
206→
207→    let mut all_records = base_records;
208→    let mut depth: u32 = 0;
209→
210→    // Step 2: Iterative deepening
211→    for d in 1..=config.max_depth {
212→        depth = d;
213→        let current_map = BehaviorMap::from_records(&analysis.name, &all_records);
214→        let mock = MockConfig {
215→            symbol: analysis.name.clone(),
216→            return_values: current_map
217→                .behaviors
218→                .iter()
219→                .filter_map(|b| b.return_value.clone())
220→                .collect(),
221→            should_track_calls: true,
222→            default_behavior: MockBehavior::RepeatLast,
223→        };
224→
225→        // Generate inputs that are slightly larger than the probe values
226→        let depth_inputs = generate_depth_inputs(&analysis.params, d);
227→        let behavior_count_before = current_map.behaviors.len();
228→        let mut found_new = false;
229→
230→        let seen_hashes: HashSet<u64> = all_records.iter().map(|r| r.input_hash).collect();
231→
232→        for inputs in depth_inputs {
233→            let input_hash = hash_inputs(&inputs);
234→            if seen_hashes.contains(&input_hash) {
235→                continue;
236→            }
237→
238→            let response = frontend
239→                .send(ProtoCommand::Execute {
240→                    function: analysis.name.clone(),
241→                    inputs: inputs.clone(),
242→                    mocks: vec![mock.clone()],
243→                    setup_context: None,
244→                })
245→                .await?;
246→
247→            let exec_result = match response.result {
248→                ResponseResult::Execute(result) => result,
249→                ResponseResult::Error { .. } => continue,
250→                _ => continue,
251→            };
252→
253→            all_records.push(make_exec_record(&analysis.name, input_hash, inputs, &exec_result));
254→        }
255→
256→        let updated_map = BehaviorMap::from_records(&analysis.name, &all_records);
257→        if updated_map.behaviors.len() > behavior_count_before {
258→            found_new = true;
259→        }
260→
261→        if !found_new {
262→            break;
263→        }
264→    }
265→
266→    let behavior_map = BehaviorMap::from_records(&analysis.name, &all_records);
267→
268→    Ok(RecursiveResult {
269→        function_name: analysis.name.clone(),
270→        behavior_map,
271→        depth_reached: depth,
272→        base_case_count,
273→        probes_executed,
274→    })
275→}
276→
277→/// Generate inputs for a given deepening depth.
278→///
279→/// At depth d, generates values around d (e.g., d, d+1, d-1 for integers)
280→/// to explore one level deeper than the previous iteration.
281→fn generate_depth_inputs(params: &[crate::types::ParamInfo], depth: u32) -> Vec<Vec<Value>> {
282→    if params.is_empty() {
283→        return vec![vec![]];
284→    }
285→
286→    let d = depth as i64;
287→    let per_param: Vec<Vec<Value>> = params
288→        .iter()
289→        .map(|p| match &p.typ {
290→            TypeInfo::Int => vec![json!(d), json!(d + 1), json!(d + 2)],
291→            TypeInfo::Float => vec![json!(d as f64), json!((d + 1) as f64)],
292→            TypeInfo::Str => {
293→                vec![json!("a".repeat(depth as usize))]
294→            }
295→            TypeInfo::Array { element } => {
296→                // Array of length `depth` with minimal elements
297→                let elem = match element.as_ref() {
298→                    TypeInfo::Int => json!(1),
299→                    TypeInfo::Str => json!("a"),
300→                    TypeInfo::Bool => json!(true),

  1→//! Behavior maps, call graphs, and compositional testing logic.
  2→//!
  3→//! When the concolic engine tests function A that calls function B, behavior maps
  4→//! let us reuse prior knowledge about B. A [`BehaviorMap`] records B's observed
  5→//! input→output mappings so that when testing A, B is mocked using its known
  6→//! behaviors. [`CallGraph`] orders functions for testing (leaves first), and
  7→//! [`BehaviorCoverage`] tracks which of B's behaviors A actually exercises.
  8→
  9→use std::collections::{HashMap, HashSet};
 10→
 11→use serde::{Deserialize, Serialize};
 12→
 13→use crate::execution_record::{
 14→    BranchDecision, ErrorInfo, ExternalCall, ExecutionRecord, SideEffect,
 15→};
 16→use crate::protocol::{ExecuteResult, MockBehavior, MockConfig};
 17→
 18→// ---------------------------------------------------------------------------
 19→// DependencyTrace
 20→// ---------------------------------------------------------------------------
 21→
 22→/// A single call to an external dependency, captured with ordering information.
 23→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 24→pub struct TracedCall {
 25→    /// Name of the called function/symbol.
 26→    pub function_name: String,
 27→    /// Arguments passed to the call.
 28→    pub arguments: Vec<serde_json::Value>,
 29→    /// Return value from the call.
 30→    pub return_value: serde_json::Value,
 31→    /// Zero-based index indicating the order of this call relative to all
 32→    /// dependency interactions (calls and side effects combined).
 33→    pub call_index: u32,
 34→}
 35→
 36→/// Categorization of a side effect.
 37→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 38→#[serde(rename_all = "snake_case")]
 39→pub enum SideEffectKind {
 40→    ConsoleOutput,
 41→    FileWrite,
 42→    NetworkRequest,
 43→    EnvironmentRead,
 44→    GlobalMutation,
 45→    ThrownError,
 46→    GlobalStateChange,
 47→}
 48→
 49→/// A side effect observed during execution, captured with ordering information.
 50→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 51→pub struct TracedSideEffect {
 52→    /// What category of side effect this is.
 53→    pub kind: SideEffectKind,
 54→    /// Human-readable description of the side effect.
 55→    pub description: String,
 56→    /// Zero-based index indicating the order of this side effect relative to
 57→    /// all dependency interactions (calls and side effects combined).
 58→    pub call_index: u32,
 59→}
 60→
 61→/// Full dependency interaction trace for a single execution.
 62→///
 63→/// Captures every external call and side effect in order, enabling
 64→/// compositional reasoning about how a function interacts with its
 65→/// dependencies.
 66→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 67→pub struct DependencyTrace {
 68→    /// External calls made during execution, in order.
 69→    pub external_calls: Vec<TracedCall>,
 70→    /// Side effects observed during execution, in order.
 71→    pub side_effects: Vec<TracedSideEffect>,
 72→    /// Total number of dependency interactions (calls + side effects),
 73→    /// useful for verifying ordering completeness.
 74→    pub call_ordering: u32,
 75→}
 76→
 77→/// Classify a [`SideEffect`] into a [`SideEffectKind`].
 78→fn side_effect_kind(effect: &SideEffect) -> SideEffectKind {
 79→    match effect {
 80→        SideEffect::ConsoleOutput { .. } => SideEffectKind::ConsoleOutput,
 81→        SideEffect::FileWrite { .. } => SideEffectKind::FileWrite,
 82→        SideEffect::NetworkRequest { .. } => SideEffectKind::NetworkRequest,
 83→        SideEffect::EnvironmentRead { .. } => SideEffectKind::EnvironmentRead,
 84→        SideEffect::GlobalMutation { .. } => SideEffectKind::GlobalMutation,
 85→        SideEffect::ThrownError { .. } => SideEffectKind::ThrownError,
 86→        SideEffect::GlobalStateChange { .. } => SideEffectKind::GlobalStateChange,
 87→    }
 88→}
 89→
 90→/// Produce a human-readable description of a [`SideEffect`].
 91→fn side_effect_description(effect: &SideEffect) -> String {
 92→    match effect {
 93→        SideEffect::ConsoleOutput { level, message } => {
 94→            format!("console.{level}: {message}")
 95→        }
 96→        SideEffect::FileWrite { path, .. } => {
 97→            format!("file write: {path}")
 98→        }
 99→        SideEffect::NetworkRequest { method, url, .. } => {
100→            format!("{method} {url}")
101→        }
102→        SideEffect::EnvironmentRead { variable, value } => {
103→            let val = value.as_deref().unwrap_or("null");
104→            format!("env read: {variable}={val}")
105→        }
106→        SideEffect::GlobalMutation { name } => {
107→            format!("mutated global: {name}")
108→        }
109→        SideEffect::ThrownError {
110→            error_type,
111→            message,
112→            ..
113→        } => {
114→            format!("{error_type}: {message}")
115→        }
116→        SideEffect::GlobalStateChange {
117→            variable,
118→            before,
119→            after,
120→        } => {
121→            format!("{variable}: {before} -> {after}")
122→        }
123→    }
124→}
125→
126→/// Build [`TracedCall`]s from a slice of [`ExternalCall`]s, starting at the
127→/// given call index offset.
128→fn build_traced_calls(calls: &[ExternalCall], start_index: u32) -> Vec<TracedCall> {
129→    calls
130→        .iter()
131→        .enumerate()
132→        .map(|(i, call)| TracedCall {
133→            function_name: call.symbol.clone(),
134→            arguments: call.args.clone(),
135→            return_value: call.return_value.clone(),
136→            call_index: start_index + i as u32,
137→        })
138→        .collect()
139→}
140→
141→/// Build [`TracedSideEffect`]s from a slice of [`SideEffect`]s, starting at
142→/// the given call index offset.
143→fn build_traced_side_effects(
144→    effects: &[SideEffect],
145→    start_index: u32,
146→) -> Vec<TracedSideEffect> {
147→    effects
148→        .iter()
149→        .enumerate()
150→        .map(|(i, effect)| TracedSideEffect {
151→            kind: side_effect_kind(effect),
152→            description: side_effect_description(effect),
153→            call_index: start_index + i as u32,
154→        })
155→        .collect()
156→}
157→
158→/// Build a [`DependencyTrace`] from an [`ExecuteResult`].
159→///
160→/// External calls are indexed first, then side effects.
161→pub fn build_dependency_trace(result: &ExecuteResult) -> DependencyTrace {
162→    let external_calls = build_traced_calls(&result.calls_to_external, 0);
163→    let se_start = external_calls.len() as u32;
164→    let side_effects = build_traced_side_effects(&result.side_effects, se_start);
165→    let call_ordering = se_start + side_effects.len() as u32;
166→
167→    DependencyTrace {
168→        external_calls,
169→        side_effects,
170→        call_ordering,
171→    }
172→}
173→
174→/// Build a [`DependencyTrace`] from an [`ExecutionRecord`].
175→///
176→/// External calls are indexed first, then side effects.
177→pub fn build_dependency_trace_from_record(record: &ExecutionRecord) -> DependencyTrace {
178→    let external_calls = build_traced_calls(&record.calls_to_external, 0);
179→    let se_start = external_calls.len() as u32;
180→    let side_effects = build_traced_side_effects(&record.side_effects, se_start);
181→    let call_ordering = se_start + side_effects.len() as u32;
182→
183→    DependencyTrace {
184→        external_calls,
185→        side_effects,
186→        call_ordering,
187→    }
188→}
