  1→//! Scope configuration: controls which files to analyze and which dependencies to mock.
  2→//!
  3→//! Reads a `shatter.scope.yaml` file that defines include/exclude globs for files
  4→//! and mock/passthrough globs for dependencies.
  5→
  6→use std::path::Path;
  7→
  8→use globset::{Glob, GlobSet, GlobSetBuilder};
  9→use serde::{Deserialize, Serialize};
 10→
 11→/// Error type for scope configuration operations.
 12→#[derive(Debug, thiserror::Error)]
 13→pub enum ScopeError {
 14→    #[error("failed to read scope file: {0}")]
 15→    Io(#[from] std::io::Error),
 16→
 17→    #[error("failed to parse scope YAML: {0}")]
 18→    Parse(#[from] serde_yaml::Error),
 19→
 20→    #[error("invalid glob pattern: {0}")]
 21→    InvalidPattern(#[from] globset::Error),
 22→}
 23→
 24→/// Top-level YAML structure wrapping the scope config under a `scope:` key.
 25→#[derive(Debug, Deserialize, Serialize)]
 26→struct ScopeFile {
 27→    scope: ScopeConfig,
 28→}
 29→
 30→/// Scope configuration defining which files and dependencies to include, exclude, mock, or pass through.
 31→#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
 32→pub struct ScopeConfig {
 33→    /// Glob patterns for files to analyze.
 34→    #[serde(default)]
 35→    pub include: Vec<String>,
 36→
 37→    /// Glob patterns for files to skip.
 38→    #[serde(default)]
 39→    pub exclude: Vec<String>,
 40→
 41→    /// Glob patterns for dependencies to mock (e.g. `"node_modules/**"`).
 42→    #[serde(default)]
 43→    pub mock: Vec<String>,
 44→
 45→    /// Glob patterns for dependencies to leave as real calls (e.g. `"lodash"`).
 46→    #[serde(default)]
 47→    pub passthrough: Vec<String>,
 48→}
 49→
 50→impl Default for ScopeConfig {
 51→    fn default() -> Self {
 52→        Self {
 53→            include: vec!["**/*.ts".to_string(), "**/*.go".to_string()],
 54→            exclude: vec!["node_modules/**".to_string(), "vendor/**".to_string()],
 55→            mock: Vec::new(),
 56→            passthrough: Vec::new(),
 57→        }
 58→    }
 59→}
 60→
 61→impl ScopeConfig {
 62→    /// Read and parse a scope configuration from a YAML file.
 63→    pub fn from_file(path: &Path) -> Result<Self, ScopeError> {
 64→        let contents = std::fs::read_to_string(path)?;
 65→        let file: ScopeFile = serde_yaml::from_str(&contents)?;
 66→        Ok(file.scope)
 67→    }
 68→}
 69→
 70→/// What to do with a dependency.
 71→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 72→pub enum DependencyAction {
 73→    /// Replace the dependency with a mock.
 74→    Mock,
 75→    /// Leave the dependency as a real call.
 76→    Passthrough,
 77→    /// No rule matched — analyze normally.
 78→    Analyze,
 79→}
 80→
 81→/// Compiled scope matcher using `GlobSet` for efficient pattern matching.
 82→pub struct ScopeMatcher {
 83→    include: GlobSet,
 84→    exclude: GlobSet,
 85→    mock: GlobSet,
 86→    passthrough: GlobSet,
 87→}
 88→
 89→impl ScopeMatcher {
 90→    /// Compile a `ScopeConfig` into a matcher.
 91→    pub fn new(config: &ScopeConfig) -> Result<Self, ScopeError> {
 92→        Ok(Self {
 93→            include: build_glob_set(&config.include)?,
 94→            exclude: build_glob_set(&config.exclude)?,
 95→            mock: build_glob_set(&config.mock)?,
 96→            passthrough: build_glob_set(&config.passthrough)?,
 97→        })
 98→    }
 99→
100→    /// Returns `true` if the path matches include patterns and does not match exclude patterns.
101→    ///
102→    /// If no include patterns are defined, all paths are considered included.
103→    pub fn is_included(&self, path: &str) -> bool {
104→        let included = self.include.is_empty() || self.include.is_match(path);
105→        let excluded = self.exclude.is_match(path);
106→        included && !excluded
107→    }
108→
109→    /// Classify a dependency symbol/path as Mock, Passthrough, or Analyze.
110→    ///
111→    /// Passthrough takes precedence over Mock (more specific override).
112→    pub fn classify_dependency(&self, symbol: &str) -> DependencyAction {
113→        if self.passthrough.is_match(symbol) {
114→            return DependencyAction::Passthrough;
115→        }
116→        if self.mock.is_match(symbol) {
117→            return DependencyAction::Mock;
118→        }
119→        DependencyAction::Analyze
120→    }
121→}
122→
123→fn build_glob_set(patterns: &[String]) -> Result<GlobSet, ScopeError> {
124→    let mut builder = GlobSetBuilder::new();
125→    for pattern in patterns {
126→        builder.add(Glob::new(pattern)?);
127→    }
128→    Ok(builder.build()?)
129→}
