  1→//! Random input generation from TypeInfo metadata.
  2→//!
  3→//! Generates random JSON values matching the type signatures reported by
  4→//! language frontends. Used for the initial exploration phase before symbolic
  5→//! constraint solving kicks in.
  6→
  7→use rand::Rng;
  8→use serde_json::{json, Value};
  9→
 10→use crate::orchestrator::FrontendCapabilities;
 11→use crate::string_mutation;
