217→/// Scope-aware path hash that collapses repeated loop/call scopes.
218→///
219→/// Parses the flat trace into a tree of nested scopes, then for each scope_id
220→/// that appears multiple times at the same nesting level, collapses all
221→/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
222→/// When `buckets` is non-empty, each distinct profile is also paired with
223→/// its iteration-count bucket so that different iteration counts produce
224→/// different hashes.
225→fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
226→    use crate::execution_record::{ScopeEvent, TraceEvent};
227→    use std::collections::BTreeSet;
228→
229→    /// Discriminant tag for scope enter/exit matching.
230→    #[derive(Clone, Copy, PartialEq)]
231→    enum ScopeKind {
232→        Loop(u32),
233→        Call(u32),
234→    }
235→
236→    /// A sorted branch profile from one loop/call iteration.
237→    type BranchProfile = Vec<(u32, bool)>;
238→
239→    /// A profile paired with its optional iteration-count bucket.
240→    type ProfileWithBucket = (BranchProfile, Option<u32>);
241→
242→    /// Collapsed representation of a scope's content for hashing.
243→    #[derive(Hash)]
244→    enum CollapsedItem {
245→        /// A branch decision outside any scope at this level.
246→        Branch { branch_id: u32, taken: bool },
247→        /// A collapsed scope: set of distinct per-iteration branch profiles,
248→        /// each paired with its iteration-count bucket (or `None` when
249→        /// bucketing is disabled, preserving backward-compat hashing).
250→        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
