266→        items: &mut Vec<CollapsedItem>,
267→        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
268→        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
269→        buckets: &LoopBuckets,
270→    ) {
271→        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
272→        for (id, profiles) in loop_profiles {
273→            let tag = (*id as u64) | (1u64 << 32);
274→            let mut sorted: Vec<ProfileWithBucket> = profiles
275→                .iter()
276→                .map(|(profile, &count)| {
277→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
278→                    (profile.clone(), bucket)
279→                })
280→                .collect();
281→            sorted.sort();
282→            scope_ids.push((tag, sorted));
283→        }
284→        for (id, profiles) in call_profiles {
285→            let tag = (*id as u64) | (2u64 << 32);
286→            let mut sorted: Vec<ProfileWithBucket> = profiles
287→                .iter()
288→                .map(|(profile, &count)| {
289→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
