301→
302→    fn collapse(events: &[TraceEvent], buckets: &LoopBuckets) -> (Vec<CollapsedItem>, usize) {
303→        let mut items: Vec<CollapsedItem> = Vec::new();
304→        let mut loop_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
